{
  "summary": "This paper proposes an automatic framework to extract symbolic knowledge graphs from pretrained language models using minimal supervision and automatic prompt paraphrasing with weighted consistency scoring. The approach supports complex and n-ary relations and demonstrates competitive accuracy and diversity of extracted knowledge across multiple datasets and models without requiring large annotated data or external knowledge bases.",
  "strengths": [
    {
      "point": "Novel unsupervised prompt generation and weighting improves knowledge extraction accuracy",
      "evidence": "Automatically generated diverse prompts outperform human-written prompts by ~9% and improve precision-recall trade-offs compared to existing baselines like COMET and LPAQA."
    },
    {
      "point": "Supports extraction of complex and n-ary relations beyond simple binary predicates",
      "evidence": "Experiments include 14 newly defined complex relations and demonstrate the framework's ability to handle multi-entity tuples."
    },
    {
      "point": "Provides interpretable symbolic knowledge graphs as an explicit representation of LM knowledge",
      "evidence": "The harvested KG enables browsing, analysis, and comparison of knowledge across different pretrained LMs."
    },
    {
      "point": "Efficient two-stage search and re-ranking strategy enables scalable candidate generation",
      "evidence": "Harvesting a KG for one relation takes about one hour on a single GPU, showing practical feasibility."
    }
  ],
  "weaknesses": [
    {
      "point": "Lacks comparison to recent prompt tuning and soft prompt optimization methods",
      "evidence": "No empirical or qualitative discussion on how the approach compares to prefix-tuning, prompt ensembling, or soft prompt optimization, weakening novelty claims."
    },
    {
      "point": "Insufficient methodological details on prompt weighting and multi-token entity handling",
      "evidence": "Missing precise formulas, normalization procedures, and explanations on how multi-token entity likelihoods and tokenization effects are computed."
    },
    {
      "point": "Limited evaluation baselines and metrics, especially for complex and n-ary relations",
      "evidence": "No comparisons to existing methods capable of handling complex relations and omission of metrics like coverage, novelty, and relation diversity."
    },
    {
      "point": "Human evaluation lacks inter-annotator agreement and quality control details",
      "evidence": "No reported agreement statistics or description of annotator qualification and spam filtering raises concerns about reliability."
    },
    {
      "point": "No qualitative error analysis or discussion of noise and hallucinated facts",
      "evidence": "Absence of error typology limits understanding of limitations and practical utility of the extracted KG."
    },
    {
      "point": "Reproducibility hindered by missing hyperparameter settings and candidate generation details",
      "evidence": "Key hyperparameters and candidate entity enumeration/pruning procedures are not explicitly described."
    },
    {
      "point": "No discussion on scalability to large-scale KG extraction or integration with downstream applications",
      "evidence": "Paper does not analyze computational requirements for thousands of relations nor explore use cases like question answering or reasoning."
    },
    {
      "point": "Generalisability limited to English LMs and common-sense/encyclopedic relations",
      "evidence": "No experiments or discussion on multilingual models or specialized domains such as biomedical or legal knowledge."
    }
  ],
  "questions": [
    {
      "question": "How does the proposed prompt paraphrasing and weighting approach compare quantitatively and qualitatively to recent prompt tuning and soft prompt optimization methods?",
      "motivation": "Understanding this is critical to establish the novelty and practical advantages of the method over state-of-the-art prompt engineering techniques."
    },
    {
      "question": "What is the impact of seed entity pair selection and number on the quality and robustness of the extracted KG?",
      "motivation": "Since seed pairs influence prompt weighting and candidate generation, ablation studies are needed to assess sensitivity and guide practical usage."
    },
    {
      "question": "How does the method handle noise and hallucinated facts in the extracted KG, and can confidence calibration or filtering improve reliability?",
      "motivation": "Downstream applications require trustworthy knowledge; addressing noise is essential for practical deployment."
    },
    {
      "question": "Can the framework scale efficiently to extract KGs with thousands of relations and millions of entities, and what strategies enable such scalability?",
      "motivation": "Scalability is crucial for real-world KG construction and adoption in large knowledge-intensive systems."
    },
    {
      "question": "How well does the approach generalize to other languages, multilingual LMs, or specialized domains?",
      "motivation": "Demonstrating broader applicability would increase the impact and relevance of the method."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
